import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import { useToast } from "../../context/ToastContext";
import { submitComplaint } from "../../services/apiService";
import { classifyComplaint } from "../../services/mlService";
import { CATEGORIES, CAT_META } from "../../utils/constants";
import { useDebounce } from "../../hooks/useDebounce";
import MLPreview from "../shared/MLPreview";
import Spinner from "../shared/Spinner";

export default function SubmitComplaint() {
  const { user }    = useAuth();
  const { showToast } = useToast();
  const navigate    = useNavigate();

  const [form, setForm]           = useState({ title: "", description: "", location: "", category: "" });
  const [mlResult, setMlResult]   = useState(null);
  const [mlLoading, setMlLoading] = useState(false);
  const [image, setImage]         = useState(null);
  const [loading, setLoading]     = useState(false);
  const [success, setSuccess]     = useState(false);
  const fileRef = useRef();

  // Debounce title+description for ML
  const debouncedText = useDebounce(`${form.title} ${form.description}`, 600);

  useEffect(() => {
    const text = debouncedText.trim();
    if (text.length < 5) { setMlResult(null); return; }
    setMlLoading(true);
    classifyComplaint(form.title, form.description).then((res) => {
      setMlResult(res);
      setMlLoading(false);
      if (res && !form.category) setForm((prev) => ({ ...prev, category: res.category }));
    });
  }, [debouncedText]); // eslint-disable-line

  const handleSubmit = async () => {
    if (!form.title || !form.description || !form.location) {
      showToast("Please fill all required fields", "⚠️");
      return;
    }
    setLoading(true);
    try {
      const fd = new FormData();
      fd.append("title",       form.title);
      fd.append("description", form.description);
      fd.append("location",    form.location);
      fd.append("category",    form.category || mlResult?.category || "Road");
      fd.append("confidence",  mlResult?.confidence || 75);
      if (image) fd.append("image", image);

      await submitComplaint(fd);
      setSuccess(true);
      showToast("Complaint submitted & ML-classified!", "🤖");
    } catch (err) {
      showToast(err.response?.data?.message || "Submission failed", "❌");
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="max-w-lg mx-auto mt-10 card p-14 text-center animate-fadeUp">
        <div className="text-5xl mb-4">✅</div>
        <h2 className="font-display font-extrabold text-2xl text-ink mb-2">Complaint Submitted!</h2>
        <p className="text-sm text-slate-500 mb-2">Your complaint has been received and classified by ML.</p>
        <div className="inline-flex items-center gap-2 bg-violet-50 text-violet-700 text-xs font-semibold px-4 py-2 rounded-full mb-7">
          🤖 Auto-classified by ML model
        </div>
        <div className="flex gap-3 justify-center">
          <button className="btn-primary" onClick={() => setSuccess(false)}>+ New Complaint</button>
          <button className="btn-ghost" onClick={() => navigate("/my-complaints")}>View My Complaints</button>
        </div>
      </div>
    );
  }

  const filled = form.title && form.description && form.location;

  return (
    <div className="max-w-2xl">
      {/* ML banner */}
      <div className="flex items-center gap-3 bg-gradient-to-r from-indigo-600 to-violet-600 rounded-xl px-5 py-4 mb-5">
        <span className="text-2xl">🤖</span>
        <div>
          <div className="font-display font-bold text-sm text-white">ML Auto-Classification Active</div>
          <div className="text-xs text-white/70">TF-IDF + Naive Bayes model classifies as you type</div>
        </div>
      </div>

      <div className="card p-7">
        <h2 className="font-display font-bold text-lg text-ink mb-5 pb-4 border-b border-slate-100">
          File a New Complaint
        </h2>

        {/* Title */}
        <div className="mb-4">
          <label className="block text-[13px] font-semibold text-ink mb-1.5">
            Complaint Title <span className="text-red-400">*</span>
          </label>
          <input
            className="input-field"
            placeholder="Brief description (e.g., Broken water pipe near school)"
            value={form.title}
            onChange={(e) => setForm({ ...form, title: e.target.value })}
          />
        </div>

        {/* Description */}
        <div className="mb-4">
          <label className="block text-[13px] font-semibold text-ink mb-1.5">
            Detailed Description <span className="text-red-400">*</span>
          </label>
          <textarea
            className="input-field resize-y min-h-[100px]"
            placeholder="Describe what happened, since when, how it affects people…"
            value={form.description}
            onChange={(e) => setForm({ ...form, description: e.target.value })}
          />
          <MLPreview result={mlResult} loading={mlLoading} />
        </div>

        {/* Location */}
        <div className="mb-4">
          <label className="block text-[13px] font-semibold text-ink mb-1.5">
            Location / Area <span className="text-red-400">*</span>
          </label>
          <input
            className="input-field"
            placeholder="e.g. Sector 4, Dehradun or Near Clock Tower"
            value={form.location}
            onChange={(e) => setForm({ ...form, location: e.target.value })}
          />
        </div>

        {/* Category picker */}
        <div className="mb-5">
          <label className="block text-[13px] font-semibold text-ink mb-1.5">
            Category{" "}
            <span className="text-[11px] text-violet-500 font-normal ml-1">
              {mlResult ? "(ML suggested — override if needed)" : "(auto-detected by ML)"}
            </span>
          </label>
          <div className="flex gap-2 flex-wrap">
            {CATEGORIES.map((cat) => {
              const s = CAT_META[cat];
              const selected = form.category === cat;
              return (
                <button
                  key={cat}
                  onClick={() => setForm({ ...form, category: cat })}
                  className="px-4 py-2 rounded-full text-sm font-semibold transition-all duration-150 cursor-pointer"
                  style={{
                    background: selected ? s.bg : "white",
                    color:      selected ? s.color : "#64748B",
                    border:     selected ? `2px solid ${s.dot}` : "1.5px solid #E2E8F0",
                  }}
                >
                  {s.icon} {cat}
                </button>
              );
            })}
          </div>
        </div>

        {/* Image upload */}
        <div className="mb-6">
          <label className="block text-[13px] font-semibold text-ink mb-1.5">
            Attach Photo <span className="text-slate-400 font-normal">(optional)</span>
          </label>
          <div
            className="border-2 border-dashed border-slate-300 rounded-xl p-6 text-center cursor-pointer
                       transition-all duration-150 hover:border-slate-400 hover:bg-slate-50"
            onClick={() => fileRef.current?.click()}
          >
            <input
              ref={fileRef}
              type="file"
              accept="image/*"
              className="hidden"
              onChange={(e) => setImage(e.target.files[0])}
            />
            <div className="text-3xl mb-2">📷</div>
            {image ? (
              <div className="text-sm text-green-600 font-semibold">{image.name}</div>
            ) : (
              <>
                <div className="text-sm text-slate-500">Click to upload or drag & drop</div>
                <div className="text-xs text-slate-400 mt-1">PNG, JPG up to 5MB</div>
              </>
            )}
          </div>
        </div>

        <button
          className="btn-primary w-full py-3 text-base"
          onClick={handleSubmit}
          disabled={loading || !filled}
          style={{ opacity: filled ? 1 : 0.6 }}
        >
          {loading ? <><Spinner /> Submitting & Classifying…</> : "Submit Complaint 🚀"}
        </button>
      </div>
    </div>
  );
}
